CREATE OR REPLACE FUNCTION fpa_get_bal_loanreq_sal_amount (as_lon_reqno char ) RETURNS bigint AS $body$
DECLARE

  ldc_balsalary bigint;
  li_count integer;
  cur_sal CURSOR FOR
  SELECT sc_lon_m_loan_request.salary_amount
  , sc_lon_m_loan_request.monthloan
  , sc_lon_m_loan_request.monthdep
  , sc_lon_m_loan_request.monthshare
  , sc_lon_m_loan_request.other_amount
  , sc_lon_m_loan_request.period_payment_amount
  , sc_lon_m_loan_request.interest_first
  from sc_lon_m_loan_request
  where loan_requestment_no = as_lon_reqno
;
  type tabrowi_sal is table of cur_sal%rowtype index by integer;ltabrowi_sal tabrowi_sal;


BEGIN
  open cur_sal;FETCH cur_sal bulk collect into ltabrowi_sal;close cur_sal;
  li_count := ltabrowi_sal.count;
  if li_count > 0 then
    ldc_balsalary := ltabrowi_sal[1].salary_amount - ltabrowi_sal[1].monthloan - ltabrowi_sal[1].monthdep - ltabrowi_sal[1].monthshare;
    ldc_balsalary := ldc_balsalary - ltabrowi_sal[1].other_amount - ltabrowi_sal[1].period_payment_amount - ltabrowi_sal[1].interest_first;
  end if;

return ldc_balsalary;




END;
$body$
